                  backgroundColor: '#fff', 
                  padding: 16, 
                  borderRadius: 10, 
                  marginBottom: 12,
                  borderLeftWidth: 4,
                  borderLeftColor: primaryColor,
                  shadowColor: '#000',
                  shadowOffset: { width: 0, height: 1 },
                  shadowOpacity: 0.1,
                  shadowRadius: 2,
                  elevation: 2
